import se.skl.rivta.testsupport.soapui.datasource.XmlDataReader
import com.eviware.soapui.support.GroovyUtils

def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/data.xml")
def callerName = testRunner.testCase.getName()
log.info("Namn = " + callerName)
if (testRunner.testCase.getPropertyValue("callerName") != null)
{
	//Anrop från annat testfall
	callerName = testRunner.testCase.getPropertyValue("callerName")
	log.info("Externt anrop från " + callerName)
}
def source = new XmlDataReader(context, dataFile)

source.load(callerName)
log.info("PatientId = " + context.patientId)
testRunner.testCase.setPropertyValue("callerName", null)

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

context.allRecords = ca.getContentRecords()

con:config.script:
def headAuthorTime = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def bodyAuthorTime = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:prescriber/urn1:authorTime'
def start = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:startOfTreatment'
def end = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:endOfTreatment'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}
if (!context.dates) {
	def headAuthorTimes = context.allRecords.collect { record -> record.firstElementAt(headAuthorTime) }
	def bodyAuthorTimes = context.allRecords.collect { record -> record.firstElementAt(bodyAuthorTime) }
	def startTimes = context.allRecords.collect { record -> record.firstElementAt(start) }
	def endTimes = context.allRecords.collect { record -> record.firstElementAt(end) }

	context.dates = (headAuthorTimes + bodyAuthorTimes + startTimes + endTimes).findAll().collect{ it[0..7] }.unique()
	log.info "Unika datum: " + context.dates

	if (!context.dates) {
		testRunner.fail("No data")
	}
}

context.datePeriodStart = context.dates.pop()
context.datePeriodEnd = context.datePeriodStart

[context.datePeriodStart, context.datePeriodEnd]

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

def authorTimeHead = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def authorTimeBody = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:prescriber/urn1:authorTime'
def start = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:startOfTreatment'
def end = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:endOfTreatment'

def id = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordHeader/urn1:documentId'

def condition = { record ->
	def ordination = record.firstElementAt(authorTimeBody) ?: record.firstElementAt(start) ?: record.firstElementAt(authorTimeHead)
	def utsattning = record.firstElementAt(end) ?: "20501231235959"

	def intervalStart = [ordination, utsattning].min()
	def intervalEnd = [ordination, utsattning].max()

	def recordIsBeforeCallInterval = intervalEnd && intervalEnd[0..7] < context.datePeriodStart
	def recordIsAfterCallInterval = intervalStart && intervalStart[0..7] > context.datePeriodEnd

	return !recordIsBeforeCallInterval && !recordIsAfterCallInterval
}

def recordInfo = { record ->
	sprintf("DocumentId %s (authorTimeHeader:%s authorTimeBody:%s start:%s end:%s)", [id, authorTimeHead, authorTimeBody, start, end].collect{record.firstElementAt(it)})
}

ca.assertFilteredResponse(context.allRecords, condition, recordInfo)

con:config.script:
if (context.dates.any()) {
	testRunner.gotoStepByName("Calculate interval")
}
else if (testRunner.getResults().any{it.getStatus().toString() == 'FAILED'}) {
	testRunner.fail("One or more steps failed")
}

