con:config.script:
def start = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:startOfTreatment'
def end = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:endOfTreatment'
def authorTimeBody = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordBody/urn1:medicationPrescription/urn1:prescriber/urn1:authorTime'
def authorTimeHead = '/urn:medicationMedicalRecord/urn1:medicationMedicalRecordHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def dateFormat = 'yyyyMMdd'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}
if (!context.iteration) {
	def startTimes = context.allRecords.collect { record -> record.firstElementAt(start) }
	def endTimes = context.allRecords.collect { record -> record.firstElementAt(end) }
	def authorTimes = context.allRecords.collect { record -> record.firstElementAt(authorTimeHead) }
	def authorTimesBody = context.allRecords.collect { record -> record.firstElementAt(authorTimeBody) }
	def dates = (startTimes + endTimes + authorTimes + authorTimesBody).findAll().collect{ it[0..7] }.sort()
	context.firstDate = Date.parse(dateFormat, dates[0])
	context.lastDate = Date.parse(dateFormat, dates[-1])
	context.iteration = 1
}

def dateDiff = context.lastDate - context.firstDate
def randomOffsets = (0..1).collect { (Math.random() * (dateDiff+1)).toInteger()}
def dates = randomOffsets.collect{ context.firstDate.plus(it).format(dateFormat) }.sort()

context.datePeriodStart = dates[0]
context.datePeriodEnd = dates[-1]

[context.datePeriodStart, context.datePeriodEnd]

