def condition = { record ->
	// Starttidpunkt = authorTimeHead och utsättningsdatum saknas
	def hasAuthorTimeBody = record.firstElementAt(authorTimeBody)
	def hasStartOfTreatment = record.firstElementAt(start)
	def hasAuthorTimeHead = record.firstElementAt(authorTimeHead)
	def hasEndOfTreatment = record.firstElementAt(end)
	return !hasAuthorTimeBody && !hasStartOfTreatment && hasAuthorTimeHead && !hasEndOfTreatment
}

def recordInfo = sprintf("Testdata saknas för testfall 8.6")

ca.assertForAnyRecord(condition, recordInfo)
